final:
module RefModule (
    input wire clk,
    input wire rstn,
    input wire serial_in,
    output reg [15:0] parallel_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rstn or posedge dbg_halt) begin
    if (!rstn)
        parallel_out <= 16'b0;
    else
        parallel_out <= {parallel_out[14:0], serial_in};
end

endmodule
